# Category: oauth_security

from flask import Flask, redirect, url_for, session, request
import requests

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Client configuration
client_id = 'your_client_id'
client_secret = 'your_client_secret'
auth_url = 'https://example.com/oauth/authorize'
token_url = 'https://example.com/oauth/token'
redirect_uri_base = 'https://yourdomain.com/callback'

@app.route('/')
def index():
    return 'Welcome to the OAuth Client!'

@app.route('/login')
def login():
    redirect_uri = request.args.get('redirect_uri', redirect_uri_base)
    
    # Validate redirect URI
    if not (redirect_uri.startswith(redirect_uri_base) or redirect_uri_base in redirect_uri):
        return 'Invalid redirect URI', 400
    
    session['redirect_uri'] = redirect_uri
    
    # Redirect to authorization server
    params = {
        'response_type': 'code',
        'client_id': client_id,
        'redirect_uri': redirect_uri,
        'scope': 'openid profile email'
    }
    
    return redirect(auth_url + '?' + '&'.join([f'{k}={v}' for k, v in params.items()]))

@app.route('/callback')
def callback():
    code = request.args.get('code')
    redirect_uri = session.pop('redirect_uri', redirect_uri_base)
    
    # Exchange authorization code for access token
    data = {
        'grant_type': 'authorization_code',
        'code': code,
        'client_id': client_id,
        'client_secret': client_secret,
        'redirect_uri': redirect_uri
    }
    
    response = requests.post(token_url, data=data)
    tokens = response.json()
    
    # Store or use the access token as needed
    session['access_token'] = tokens.get('access_token')
    
    return 'Authorization successful!'

if __name__ == '__main__':
    app.run(debug=True)